var e=JSON.parse(`[{"id":"L3_1","type":"dialog","speaker":"UNCLE_NPC_NULL_NULL","text":{"KOREA":"레이라면 지금쯤 이 근처에서 열매를 따고 있을 게다.","JPN":"レイだったら今頃この近くで実を採っているはずだ。","ENG":"Knowing Ray, he should be picking berries somewhere around here about now.","TWN":"雷伊應該正在附近採果實。"},"stage":{"bg":"FOREST_NORMAL","slots":{"L":{"char_id":"UNCLE_NPC_NULL_NULL","face":"UNIT_IDLE"},"C":null,"R":{"char_id":"ALLEN_SCHOOL_NPC_NULL","face":"UNIT_IDLE"}}}},{"id":"L4_1","type":"dialog","speaker":"ALLEN_SCHOOL_NPC_NULL","text":{"KOREA":"이 시기에는 열매가 아주 실하게 익죠. 기억납니다, 숙부님.","JPN":"この時期は実がおいしく熟しますよね。思い出しました、叔父さん。","ENG":"Around this time of year, fruits ripen beautifully. I remember, Uncle.","TWN":"我記得現在是果實正好成熟的時期呢，叔叔。"},"stage":{"bg":"FOREST_NORMAL","slots":{"L":{"char_id":"UNCLE_NPC_NULL_NULL","face":"UNIT_IDLE"},"C":null,"R":{"char_id":"ALLEN_SCHOOL_NPC_NULL","face":"UNIT_IDLE"}}}},{"id":"L5_1","type":"dialog","speaker":"UNCLE_NPC_NULL_NULL","text":{"KOREA":"하하, 센트럴 팰리스에서는 흙냄새도 맡기 힘들다지?","JPN":"はは、セントラルパレスでは土の匂いも感じないと言っていたな？","ENG":"Haha, I’ve heard it’s difficult to even get a whiff of dirt in Central Palace, eh?","TWN":"哈哈～在聖特羅貝里斯應該很難聞到泥土的味道吧？"},"stage":{"bg":"FOREST_NORMAL","slots":{"L":{"char_id":"UNCLE_NPC_NULL_NULL","face":"UNIT_IDLE"},"C":null,"R":{"char_id":"ALLEN_SCHOOL_NPC_NULL","face":"UNIT_IDLE"}}}},{"id":"L6_1","type":"dialog","speaker":"UNCLE_NPC_NULL_NULL","text":{"KOREA":"영주님네 마구간지기와 네가 며칠 뒤에 도망쳐 올지 내기했는데, 벌써 몇 년은 지났구나.","JPN":"お前が何日後に逃げてくるか、領主様の馬屋番と賭けをしたものだが、もう何年も過ぎたとはなあ。","ENG":"I made a bet with our lord's stable keeper on how many days it would be until you came running back, but that was years ago.","TWN":"我那時還和領主家的僕人還打賭，賭你什麼時候會逃回來呢？這都已經過幾年啦？"},"stage":{"bg":"FOREST_NORMAL","slots":{"L":{"char_id":"UNCLE_NPC_NULL_NULL","face":"UNIT_IDLE"},"C":null,"R":{"char_id":"ALLEN_SCHOOL_NPC_NULL","face":"UNIT_IDLE"}}}},{"id":"L7_1","type":"dialog","speaker":"ALLEN_SCHOOL_NPC_NULL","text":{"KOREA":"아내도, 아내의 가문도 저를 인정해 줬습니다. 힘들다고 달아나는 건 무책임한 짓이죠.","JPN":"妻も妻の一門も私を認めてくれました。大変だからといって逃げるのは無責任でしょう。","ENG":"My wife and her family have both acknowledged me. It would have been irresponsible to run away because things were difficult.","TWN":"現在妻子和妻子的家族都已經認同我，況且因為辛苦就逃走，這樣未免太不負責任。"},"stage":{"bg":"FOREST_NORMAL","slots":{"L":{"char_id":"UNCLE_NPC_NULL_NULL","face":"UNIT_IDLE"},"C":null,"R":{"char_id":"ALLEN_SCHOOL_NPC_NULL","face":"UNIT_HATE"}}}},{"id":"L8_1","type":"dialog","speaker":"ALLEN_SCHOOL_NPC_NULL","text":{"KOREA":"기왕 출세할 기회를 얻었으니 죽을 각오로 버티라고 당부해 주신 건 숙부님 아니셨습니까?","JPN":"せっかく出世する機会を得たのだから、死ぬ覚悟で耐えろと言ってくださったのは叔父さんでしたよね？","ENG":"Uncle, weren't you the one who told me to persevere with everything I've got because I'd been given a chance to succeed?","TWN":"而且不是叔叔你說，既然有機會可以出人頭地，那死也要撐下去的嗎？"},"stage":{"bg":"FOREST_NORMAL","slots":{"L":{"char_id":"UNCLE_NPC_NULL_NULL","face":"UNIT_IDLE"},"C":null,"R":{"char_id":"ALLEN_SCHOOL_NPC_NULL","face":"UNIT_SERIOUS"}}}},{"id":"L9_1","type":"dialog","speaker":"UNCLE_NPC_NULL_NULL","text":{"KOREA":"크흠. 귀족 집안에 데릴사위로 들어가 놓고 마누라랑 그렇게 사이가 좋을지 누가 알았나.","JPN":"こほん。貴族の家柄に婿養子として入っておいて、妻とそんなに仲良くなるとは嬉しい誤算だな。","ENG":"Ahem. Who knew that you would have such a good relationship with your wife after you moved in with your noble in-laws?","TWN":"咳咳，誰知道你入贅貴族之家後，和妻子的感情會那麼好？"},"stage":{"bg":"FOREST_NORMAL","slots":{"L":{"char_id":"UNCLE_NPC_NULL_NULL","face":"UNIT_IDLE"},"C":null,"R":{"char_id":"ALLEN_SCHOOL_NPC_NULL","face":"UNIT_SERIOUS"}}}},{"id":"L10_1","type":"dialog","speaker":"UNCLE_NPC_NULL_NULL","text":{"KOREA":"너는 확실히 양이나 치면서 살다 죽기엔 아까운 놈이야.","JPN":"お前は確かに羊飼いなどで一生を終えるには惜しいやつだ。","ENG":"However, there is no doubt that you were meant for more than just shepherding for the rest of your life.","TWN":"你確實是難得一見的人才沒錯。"},"stage":{"bg":"FOREST_NORMAL","slots":{"L":{"char_id":"UNCLE_NPC_NULL_NULL","face":"UNIT_IDLE"},"C":null,"R":{"char_id":"ALLEN_SCHOOL_NPC_NULL","face":"UNIT_SERIOUS"}}}},{"id":"L11_1","type":"dialog","speaker":"ALLEN_SCHOOL_NPC_NULL","text":{"KOREA":"남들과 같은 결혼 생활은 아닙니다. 아내나 저나 서로를 둘도 없는 전우로 여기니 말입니다.","JPN":"一般的な結婚生活ではありません。妻も私もお互いをかけがえのない戦友と思っていますから。","ENG":"My marriage is not like the marriages of others. My wife and I consider each other as irreplaceable comrades.","TWN":"我的婚姻跟一般人不太一樣，我和妻子視彼此為唯一的戰友。"},"stage":{"bg":"FOREST_NORMAL","slots":{"L":{"char_id":"UNCLE_NPC_NULL_NULL","face":"UNIT_IDLE"},"C":null,"R":{"char_id":"ALLEN_SCHOOL_NPC_NULL","face":"UNIT_DESPAIR"}}}},{"id":"L12_1","type":"dialog","speaker":"UNCLE_NPC_NULL_NULL","text":{"KOREA":"남녀 사이에 전우는 무슨. 그런 입에 발린 말은 듣기도 싫다.","JPN":"男女間で戦友など。そんな心にもないお世辞は聞きたくもない。","ENG":"Pfft! Comradery between men and women? Now you’re just talking nonsense.","TWN":"男女之間說什麼戰友，這是在曬恩愛嗎？真討厭。"},"stage":{"bg":"FOREST_NORMAL","slots":{"L":{"char_id":"UNCLE_NPC_NULL_NULL","face":"UNIT_IDLE"},"C":null,"R":{"char_id":"ALLEN_SCHOOL_NPC_NULL","face":"UNIT_DESPAIR"}}}},{"id":"L13_1","type":"dialog","speaker":"UNCLE_NPC_NULL_NULL","text":{"KOREA":"그보다…… 정말 레이를 데려갈 생각이냐?","JPN":"それより……本当にレイを連れて行くつもりか？","ENG":"Anyway... Are you really thinking of taking Ray with you?","TWN":"不過……你真的打算要帶上雷伊嗎？"},"stage":{"bg":"FOREST_NORMAL","slots":{"L":{"char_id":"UNCLE_NPC_NULL_NULL","face":"UNIT_IDLE"},"C":null,"R":{"char_id":"ALLEN_SCHOOL_NPC_NULL","face":"UNIT_DESPAIR"}}}},{"id":"L14_1","type":"dialog","speaker":"ALLEN_SCHOOL_NPC_NULL","text":{"KOREA":"네, 이미 짐도 꾸려 두었습니다.","JPN":"はい、すでに荷物もまとめてあります。","ENG":"Yes, I have already packed his bags.","TWN":"是，行李也都打包好了。"},"stage":{"bg":"FOREST_NORMAL","slots":{"L":{"char_id":"UNCLE_NPC_NULL_NULL","face":"UNIT_IDLE"},"C":null,"R":{"char_id":"ALLEN_SCHOOL_NPC_NULL","face":"UNIT_IDLE"}}}},{"id":"L15_1","type":"dialog","speaker":"ALLEN_SCHOOL_NPC_NULL","text":{"KOREA":"마왕의 추종자들 탓에 오는 길이 지체되었으니, 오늘 바로 함께 수도로 떠날 예정입니다.","JPN":"魔王の取り巻きのせいで来るのが遅れてしまったので、今日にでも一緒に首都に発つ予定です。","ENG":"As we were delayed by the Demon Lord followers on our way over, we will head out for the capital today.","TWN":"都怪魔王的追隨者，害我在來的路上耽擱，所以今天就必須立刻出發去首都。"},"stage":{"bg":"FOREST_NORMAL","slots":{"L":{"char_id":"UNCLE_NPC_NULL_NULL","face":"UNIT_IDLE"},"C":null,"R":{"char_id":"ALLEN_SCHOOL_NPC_NULL","face":"UNIT_IDLE"}}}},{"id":"L16_1","type":"dialog","speaker":"UNCLE_NPC_NULL_NULL","text":{"KOREA":"솔직히 말하자면 정말 그 아이를 보내도 될지 모르겠다.","JPN":"正直言うと、本当にあの子を送ってもいいのかわからない。","ENG":"To be honest, I’m not sure if sending the boy is a great idea.","TWN":"說老實話，我不知道到底該不該讓他去。"},"stage":{"bg":"FOREST_NORMAL","slots":{"L":{"char_id":"UNCLE_NPC_NULL_NULL","face":"UNIT_IDLE"},"C":null,"R":{"char_id":"ALLEN_SCHOOL_NPC_NULL","face":"UNIT_IDLE"}}}},{"id":"L17_1","type":"dialog","speaker":"UNCLE_NPC_NULL_NULL","text":{"KOREA":"너와는 달리 수도에서 살기엔 너무 유약한 녀석인데.","JPN":"お前とは違って、首都で暮らすには軟弱すぎるやつだからな。","ENG":"Unlike you, he’s too soft to live in the capital.","TWN":"那孩子和你不同，恐怕沒辦法適應首都的生活。"},"stage":{"bg":"FOREST_NORMAL","slots":{"L":{"char_id":"UNCLE_NPC_NULL_NULL","face":"UNIT_IDLE"},"C":null,"R":{"char_id":"ALLEN_SCHOOL_NPC_NULL","face":"UNIT_IDLE"}}}},{"id":"L18_1","type":"dialog","speaker":"ALLEN_SCHOOL_NPC_NULL","text":{"KOREA":"너무 걱정하지 마십시오. 레이는 강합니다.","JPN":"あまり心配しないでください。レイは強い子です。","ENG":"Do not worry. Ray is strong.","TWN":"叔叔你別擔心，雷伊很堅強的。"},"stage":{"bg":"FOREST_NORMAL","slots":{"L":{"char_id":"UNCLE_NPC_NULL_NULL","face":"UNIT_IDLE"},"C":null,"R":{"char_id":"ALLEN_SCHOOL_NPC_NULL","face":"UNIT_SERIOUS"}}}},{"id":"L19_1","type":"dialog","speaker":"UNCLE_NPC_NULL_NULL","text":{"KOREA":"사냥해 온 사슴 모가지도 못 꺾고 쩔쩔 매는 녀석이?","JPN":"狩ってきた鹿の首も折れず、うろたえているやつがか？","ENG":"You mean the kid who even struggles to finish off the deer he brought back from a hunt?","TWN":"你是說獵到鹿後，連扭斷鹿脖子都不敢，在一旁手足無措的小子？"},"stage":{"bg":"FOREST_NORMAL","slots":{"L":{"char_id":"UNCLE_NPC_NULL_NULL","face":"UNIT_IDLE"},"C":null,"R":{"char_id":"ALLEN_SCHOOL_NPC_NULL","face":"UNIT_SERIOUS"}}}},{"id":"L20_1","type":"dialog","speaker":"ALLEN_SCHOOL_NPC_NULL","text":{"KOREA":"심성이 착할 뿐이죠.","JPN":"心根が優しいだけでしょう。","ENG":"He is merely kind-hearted.","TWN":"那是因為他心地善良。"},"stage":{"bg":"FOREST_NORMAL","slots":{"L":{"char_id":"UNCLE_NPC_NULL_NULL","face":"UNIT_IDLE"},"C":null,"R":{"char_id":"ALLEN_SCHOOL_NPC_NULL","face":"UNIT_DESPAIR"}}}},{"id":"L21_1","type":"dialog","speaker":"UNCLE_NPC_NULL_NULL","text":{"KOREA":"고통스럽게 죽어갈 바에 일찍 죽는 게 낫지. 그건 착한 게 아니라 어리석다고 하는 게야.","JPN":"苦しんで死んでいくよりは早く死ぬ方がいいだろう。そういうのは、優しいんじゃなくて愚かというんだ。","ENG":"It’s better to finish it off quickly than to let it suffer until the end. That’s being foolish, not kind-hearted.","TWN":"那不是善良，而是愚蠢。與其增加牠的痛苦，不如讓牠痛快一點，反正結局都是死。"},"stage":{"bg":"FOREST_NORMAL","slots":{"L":{"char_id":"UNCLE_NPC_NULL_NULL","face":"UNIT_IDLE"},"C":null,"R":{"char_id":"ALLEN_SCHOOL_NPC_NULL","face":"UNIT_DESPAIR"}}}}]`);export{e as default};